def solution(arr, N, M):
    for i in range(N):
        min_idx = i
        for j in range(i + 1, N):
            if arr[min_idx] > arr[j]:
                min_idx = j
        arr[i], arr[min_idx] = arr[min_idx], arr[i]

    answer = 0
    for i in range(1, N):
        if i % M == 0:
            answer += i # 이 줄을 수정하세요.
    return answer

